def gen(rng, size):
    n = rng.randint(2, max(2, min(size, 400)))
    vals = rng.sample(range(0, 100001), min(n, 100001))
    class N:
        __slots__ = ('v', 'l', 'r')
        def __init__(self, v):
            self.v = v; self.l = None; self.r = None
    root = None
    def ins(node, v):
        if node is None:
            return N(v)
        if v < node.v:
            node.l = ins(node.l, v)
        else:
            node.r = ins(node.r, v)
        return node
    for v in vals:
        root = ins(root, v)
    out = []
    q = [root]
    while q:
        node = q.pop(0)
        if node is None:
            out.append(None)
            continue
        out.append(node.v)
        q.append(node.l)
        q.append(node.r)
    while out and out[-1] is None:
        out.pop()
    return [out]

