class Solution:
    def getMinimumDifference(self, root):
        self.prev = None
        self.best = float('inf')
        def inorder(node):
            if node is None:
                return
            inorder(node.left)
            if self.prev is not None:
                self.best = min(self.best, node.val - self.prev)
            self.prev = node.val
            inorder(node.right)
        inorder(root)
        return self.best

