var getMinimumDifference = function(root) {
    let prev = null;
    let best = Infinity;
    const inorder = (node) => {
        if (node === null) return;
        inorder(node.left);
        if (prev !== null) best = Math.min(best, node.val - prev);
        prev = node.val;
        inorder(node.right);
    };
    inorder(root);
    return best;
};
